+import {
+  createAttachedChannelResultAdapter,
+  type ChannelOutboundAdapter,
+} from "openclaw/plugin-sdk/channel-send-result";
+import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
+import { resolveOutboundSendDep } from "openclaw/plugin-sdk/infra-runtime";
+
+type WhatsAppChunker = NonNullable<ChannelOutboundAdapter["chunker"]>;
+type WhatsAppSendTextOptions = {
+  verbose: boolean;
+  cfg?: OpenClawConfig;
+  mediaUrl?: string;
+  mediaAccess?: {
+    localRoots?: readonly string[];
+    readFile?: (filePath: string) => Promise<Buffer>;
+  };
+  mediaLocalRoots?: readonly string[];
+  mediaReadFile?: (filePath: string) => Promise<Buffer>;
+  gifPlayback?: boolean;
+  accountId?: string;
+};
+type WhatsAppSendMessage = (
+  to: string,
+  body: string,
+  options: WhatsAppSendTextOptions,
+) => Promise<{ messageId: string; toJid: string }>;
+type WhatsAppSendPoll = (
+  to: string,
+  poll: Parameters<NonNullable<ChannelOutboundAdapter["sendPoll"]>>[0]["poll"],
+  options: { verbose: boolean; accountId?: string; cfg?: OpenClawConfig },
+) => Promise<{ messageId: string; toJid: string }>;
+
+type CreateWhatsAppOutboundBaseParams = {
+  chunker: WhatsAppChunker;
+  sendMessageWhatsApp: WhatsAppSendMessage;
+  sendPollWhatsApp: WhatsAppSendPoll;
+  shouldLogVerbose: () => boolean;
+  resolveTarget: ChannelOutboundAdapter["resolveTarget"];
+  normalizeText?: (text: string | undefined) => string;
+  skipEmptyText?: boolean;
+};
+
+export function createWhatsAppOutboundBase({
+  chunker,
+  sendMessageWhatsApp,
+  sendPollWhatsApp,
+  shouldLogVerbose,
+  resolveTarget,
+  normalizeText = (text) => text ?? "",
+  skipEmptyText = false,
+}: CreateWhatsAppOutboundBaseParams): Pick<
+  ChannelOutboundAdapter,
+  | "deliveryMode"
+  | "chunker"
+  | "chunkerMode"
+  | "textChunkLimit"
+  | "pollMaxOptions"
+  | "resolveTarget"
+  | "sendText"
+  | "sendMedia"
+  | "sendPoll"
+> {
+  return {
+    deliveryMode: "gateway",
+    chunker,
+    chunkerMode: "text",
+    textChunkLimit: 4000,
+    pollMaxOptions: 12,
+    resolveTarget,
+    ...createAttachedChannelResultAdapter({
+      channel: "whatsapp",
+      sendText: async ({ cfg, to, text, accountId, deps, gifPlayback }) => {
+        const normalizedText = normalizeText(text);
+        if (skipEmptyText && !normalizedText) {
+          return { messageId: "" };
+        }
+        const send =
+          resolveOutboundSendDep<WhatsAppSendMessage>(deps, "whatsapp") ?? sendMessageWhatsApp;
+        return await send(to, normalizedText, {
+          verbose: false,
+          cfg,
+          accountId: accountId ?? undefined,
+          gifPlayback,
+        });
+      },
+      sendMedia: async ({
+        cfg,
+        to,
+        text,
+        mediaUrl,
+        mediaAccess,
+        mediaLocalRoots,
+        mediaReadFile,
+        accountId,
+        deps,
+        gifPlayback,
+      }) => {
+        const send =
+          resolveOutboundSendDep<WhatsAppSendMessage>(deps, "whatsapp") ?? sendMessageWhatsApp;
+        return await send(to, normalizeText(text), {
+          verbose: false,
+          cfg,
+          mediaUrl,
+          mediaAccess,
+          mediaLocalRoots,
+          mediaReadFile,
+          accountId: accountId ?? undefined,
+          gifPlayback,
+        });
+      },
+      sendPoll: async ({ cfg, to, poll, accountId }) =>
+        await sendPollWhatsApp(to, poll, {
+          verbose: shouldLogVerbose(),
+          accountId: accountId ?? undefined,
+          cfg,
+        }),
+    }),
+  };
+}

